insert into public.events
  (external_id, name, description, organizer_name, address, city, state, latitude, longitude,
   start_datetime, end_datetime, event_status, visibility_status, parking_info, admission_info,
   market_type, hours_summary, website_url, extra_info, external_source, last_synced_at, sync_metadata)
select
  v.external_id,
  v.name,
  v.description,
  v.organizer_name,
  v.address,
  v.city,
  v.state,
  v.latitude,
  v.longitude,
  v.start_datetime::timestamptz,
  v.end_datetime::timestamptz,
  v.event_status,
  v.visibility_status,
  v.parking_info,
  v.admission_info,
